#include<bits/stdc++.h>
using namespace std;
string A,B,jz="0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
int jw,a[2005],b[2005],c[2005];
int main(){
	cin>>jw>>A>>B;
	int k=A.size(),j=B.size();
	for(int i=1;i<=k;i++){
		a[i]=A[k-i]-(A[k-i]>='0'&&A[k-i]<='9'?'0':('A'-10));
	}
	for(int i=1;i<=j;i++){
		b[i]=B[j-i]-(B[j-i]>='0'&&B[j-i]<='9'?'0':('A'-10));
	}
	int l=max(k,j);
	for(int i=1;i<=l;i++){
		c[i]=a[i]+b[i];
	}
	for(int i=1;i<l;i++){
		if(c[i]>=jw){
			c[i+1]+=c[i]/jw,c[i]%=jw;
		}
	}
	while(c[l]>=jw){
		c[l+1]+=c[l]/jw,c[l]%=jw,l++;
	}
	while(!c[l])l--;
	for(int i=l;i>0;i--)cout<<jz[c[i]];
	return 0;
}
